def find_candidate_keys(attributes, fds):
    '''
    Find all candidate keys given set of attributes and FDs
    attributes: set of all attributes
    fds: list of (lhs, rhs) tuples
    '''
    # Compute closure of a set of attributes
    def closure(attrs, fds):
        result = set(attrs)
        changed = True
        while changed:
            changed = False
            for lhs, rhs in fds:
                if lhs.issubset(result) and not rhs.issubset(result):
                    result = result.union(rhs)
                    changed = True
        return result

    # Check if attribute set is a superkey
    def is_superkey(attrs):
        return closure(attrs, fds) == attributes

    # Check if minimal (no proper subset is superkey)
    def is_candidate_key(attrs):
        if not is_superkey(attrs):
            return False
        for attr in attrs:
            if is_superkey(attrs - {attr}):
                return False
        return True

    # Find all candidate keys
    from itertools import combinations
    candidate_keys = []
    for size in range(1, len(attributes) + 1):
        for combo in combinations(attributes, size):
            if is_candidate_key(set(combo)):
                candidate_keys.append(set(combo))

    return candidate_keys

# Example usage
attributes = {'A', 'B', 'C', 'D'}
fds = [({'A'}, {'B'}), ({'B'}, {'C'}), ({'C'}, {'D'})]
print(find_candidate_keys(attributes, fds))  # Output: [{'A'}]

#include <stdio.h>
#include <stdbool.h>
#include <string.h>

#define MAX_ATTRS 10
#define MAX_FDS 20

// Structure to represent a set of attributes
typedef struct {
    char attrs[MAX_ATTRS];
    int count;
} AttrSet;

// Structure for Functional Dependency
typedef struct {
    AttrSet lhs;
    AttrSet rhs;
} FD;

// Check if attr is in set
bool contains(AttrSet set, char attr) {
    for (int i = 0; i < set.count; i++) {
        if (set.attrs[i] == attr) return true;
    }
    return false;
}

// Compute closure of attribute set under given FDs
AttrSet closure(AttrSet input, FD fds[], int fd_count, AttrSet all_attrs) {
    AttrSet result = input;
    bool changed = true;

    while (changed) {
        changed = false;
        for (int i = 0; i < fd_count; i++) {
            // Check if LHS is subset of result
            bool lhs_in_result = true;
            for (int j = 0; j < fds[i].lhs.count; j++) {
                if (!contains(result, fds[i].lhs.attrs[j])) {
                    lhs_in_result = false;
                    break;
                }
            }
            // If LHS in result and RHS not, add RHS
            if (lhs_in_result) {
                for (int j = 0; j < fds[i].rhs.count; j++) {
                    if (!contains(result, fds[i].rhs.attrs[j])) {
                        result.attrs[result.count++] = fds[i].rhs.attrs[j];
                        changed = true;
                    }
                }
            }
        }
    }
    return result;
}

// Check if set X is a superkey
bool isSuperkey(AttrSet X, FD fds[], int fd_count, AttrSet all_attrs) {
    AttrSet X_closure = closure(X, fds, fd_count, all_attrs);
    return X_closure.count == all_attrs.count;
}

// Check if relation is in BCNF
bool isInBCNF(FD fds[], int fd_count, AttrSet all_attrs) {
    printf("\nChecking BCNF compliance:\n");
    for (int i = 0; i < fd_count; i++) {
        printf("FD %c -> %c: ", fds[i].lhs.attrs[0], fds[i].rhs.attrs[0]);
        if (isSuperkey(fds[i].lhs, fds, fd_count, all_attrs)) {
            printf("BCNF compliant (LHS is superkey)\n");
        } else {
            printf("BCNF VIOLATION! (LHS is not superkey)\n");
            return false;
        }
    }
    return true;
}

int main() {
    // Example: R(A,B,C) with FD B -> C
    // This violates BCNF as B is not a superkey
    AttrSet all_attrs = {'A', 'B', 'C'}, 3;
    FD fds[1] = {{{'B'}, 1}, {{'C'}, 1}};

    if (isInBCNF(fds, 1, all_attrs)) {
        printf("\nRelation is in BCNF\n");
    } else {
        printf("\nRelation is NOT in BCNF\n");
    }

    return 0;
}
